import React from "react";
import { Hammer, Home, Wrench, ClipboardList, Box, Building, ArrowUpRight } from "lucide-react";

import constructionMgmtImg from "../../images/framing.jpg";
import customMillworkImg from "../../images/customcabinets.jpg";
import basementsAdditionsImg from "../../images/pic26.jpeg";

const services = [
  {
    icon: Wrench,
    title: "Full Structural Guts",
    body: "Complete interior tear-downs down to the studs. Complex load-bearing wall removals, structural reframing, and mechanical rough-ins to prepare the canvas.",
    img: "https://images.unsplash.com/photo-1768677903496-becc4be07258?crop=entropy&cs=srgb&fm=jpg&ixid=M3w3NDk1ODB8MHwxfHNlYXJjaHwxfHxjb21tZXJjaWFsJTIwY29uc3RydWN0aW9uJTIwc2l0ZXxlbnwwfHx8fDE3ODA5MjQ1MjJ8MA&ixlib=rb-4.1.0&q=85",
    featured: true,
  },
  {
    icon: Hammer,
    title: "Interior Redesign & Remodelling",
    body: "Whole-home remodelling and interior renovations. Transforming existing footprints with millimeter-tight precision, custom millwork, and premium finishes.",
    img: "https://images.unsplash.com/photo-1628744876497-eb30460be9f6?crop=entropy&cs=srgb&fm=jpg&ixid=M3w3NDk1Nzh8MHwxfHNlYXJjaHwxfHxtb2Rlcm4lMjBpbnRlcmlvciUyMGx1eHVyeSUyMHJlbm92YXRpb258ZW58MHx8fHwxNzgwOTI0NTIyfDA&ixlib=rb-4.1.0&q=85",
  },
  {
    icon: Home,
    title: "Exterior Transformations",
    body: "Elevating curb appeal while fortifying structural integrity. From architectural window installations and contemporary siding to complete outdoor living extensions.",
    img: "https://images.unsplash.com/photo-1574120583586-de8847ae992c?crop=entropy&cs=srgb&fm=jpg&ixid=M3w4NjAzMjh8MHwxfHNlYXJjaHwxfHxvdXRkb29yJTIwZGVjayUyMGhvdXNlJTIwZXh0ZXJpb3J8ZW58MHx8fHwxNzgwOTI0NTQxfDA&ixlib=rb-4.1.0&q=85",
  },
  {
    icon: ClipboardList,
    title: "Construction Management",
    body: "End-to-end superintendence: trades, schedule, budget, inspections and quality closeout — built on high-rise enterprise discipline.",
    img: constructionMgmtImg,
  },
  {
    icon: Box,
    title: "Custom Millwork & Cabinetry",
    body: "Bespoke cabinetry and built-ins tailored to your space. We integrate smart storage and refined aesthetics for a truly custom living experience.",
    img: customMillworkImg,
  },
  {
    icon: Building,
    title: "Basements & Additions",
    body: "Maximizing square footage. Whether it's a basement conversion or a home addition, we ensure seamless structural integration and code compliance.",
    img: basementsAdditionsImg,
  },
];

// ─── FEATURED (wide) card ────────────────────────────────────────────────────
function FeaturedCard({ service, index }) {
  const Icon = service.icon;
  return (
    <article
      data-testid={`service-card-${index}`}
      className="reveal group bg-white border border-brand-line md:col-span-2 flex flex-col md:flex-row transition-all duration-500 hover:border-brand-ink overflow-hidden"
    >
      {/* Image takes left 55% on desktop */}
      <div className="w-full md:w-[55%] overflow-hidden bg-brand-surface2 aspect-[4/3] md:aspect-auto md:min-h-[380px] shrink-0">
        <img
          src={service.img}
          alt={service.title}
          loading="lazy"
          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
        />
      </div>

      {/* Text — right panel */}
      <div className="flex flex-col justify-between p-8 md:p-10 lg:p-12 flex-1">
        <div>
          <div className="flex items-center justify-between mb-6">
            <Icon size={24} className="text-brand-ink" strokeWidth={1.5} />
            <span className="text-xs tracking-widest uppercase text-brand-muted">
              0{index + 1} — Signature Service
            </span>
          </div>
          <h3 className="font-display text-3xl md:text-4xl font-medium text-brand-ink leading-tight">
            {service.title}
          </h3>
          <p className="mt-5 text-base leading-relaxed text-brand-smoke">
            {service.body}
          </p>
        </div>

        {/* Subtle callout badge */}
        <div className="mt-8 flex items-end justify-between gap-6">
          <div className="flex flex-col gap-1">
            <span className="text-xs uppercase tracking-[0.22em] text-brand-muted">
              What's included
            </span>
            <div className="flex flex-wrap gap-2 mt-2">
              {["Structural assessment", "Load-bearing removals", "Mechanical rough-in", "Full permit handling"].map((tag) => (
                <span
                  key={tag}
                  className="text-xs px-3 py-1.5 border border-brand-line text-brand-smoke"
                >
                  {tag}
                </span>
              ))}
            </div>
          </div>
          <a
            href="#contact"
            data-testid={`service-cta-${index}`}
            className="shrink-0 inline-flex items-center gap-2 text-sm font-medium text-brand-ink group-hover:text-brand-accent transition-colors"
          >
            Discuss your scope
            <ArrowUpRight
              size={16}
              className="transition-transform duration-300 group-hover:translate-x-0.5 group-hover:-translate-y-0.5"
            />
          </a>
        </div>
      </div>
    </article>
  );
}

// ─── STANDARD card ───────────────────────────────────────────────────────────
function StandardCard({ service, index }) {
  const Icon = service.icon;
  return (
    <article
      data-testid={`service-card-${index}`}
      className="reveal group bg-white border border-brand-line p-8 md:p-10 flex flex-col transition-all duration-500 hover:border-brand-ink hover:-translate-y-1"
    >
      <div className="aspect-[4/3] w-full overflow-hidden mb-8 bg-brand-surface2">
        <img
          src={service.img}
          alt={service.title}
          loading="lazy"
          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
        />
      </div>
      <div className="flex items-center justify-between mb-5">
        <Icon size={22} className="text-brand-ink" strokeWidth={1.5} />
        <span className="text-xs tracking-widest uppercase text-brand-muted">
          0{index + 1}
        </span>
      </div>
      <h3 className="font-display text-2xl md:text-[26px] font-medium text-brand-ink leading-tight">
        {service.title}
      </h3>
      <p className="mt-4 text-base leading-relaxed text-brand-smoke flex-1">
        {service.body}
      </p>
      <a
        href="#contact"
        data-testid={`service-cta-${index}`}
        className="mt-8 inline-flex items-center gap-2 text-sm font-medium text-brand-ink group-hover:text-brand-accent transition-colors"
      >
        Discuss your scope
        <ArrowUpRight
          size={16}
          className="transition-transform duration-300 group-hover:translate-x-0.5 group-hover:-translate-y-0.5"
        />
      </a>
    </article>
  );
}

// ─── MAIN EXPORT ─────────────────────────────────────────────────────────────
export default function Services() {
  const [featured, ...rest] = services;

  return (
    <section
      id="services"
      data-testid="services-section"
      className="bg-brand-surface py-28 md:py-40"
    >
      <div className="max-w-7xl mx-auto px-6 md:px-10">
        <div className="flex flex-col md:flex-row md:items-end md:justify-between gap-8 mb-16 md:mb-24">
          <div className="reveal max-w-2xl">
            <div className="flex items-center gap-3 mb-6">
              <span className="block w-10 h-px bg-brand-accent" />
              <span className="text-xs tracking-[0.28em] uppercase text-brand-smoke font-medium">
                Our Capabilities
              </span>
            </div>
            <h2 className="font-display text-4xl md:text-5xl lg:text-6xl font-medium text-brand-ink tracking-tighter leading-[1.05]">
              Built from the studs up.
            </h2>
          </div>
          <p className="text-base md:text-lg text-brand-smoke max-w-sm reveal pb-2">
            We bring enterprise-grade discipline to residential builds. From structural guts to final finish.
          </p>
        </div>

        {/* Grid: featured card spans 2 cols, rest fill remaining */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8">
          <FeaturedCard service={featured} index={0} />
          {rest.map((s, i) => (
            <StandardCard key={s.title} service={s} index={i + 1} />
          ))}
        </div>

      </div>
    </section>
  );
}
